mapper.select:
SELECT COUNT(1)
FROM TAG_MASTER
WHERE TAG_CODE = #{value}

mapper.delete:
DELETE FROM
USER_TAG_MAP
WHERE USER_NO = (
SELECT ua.USER_NO
FROM USER_AUTHENTICATION
ua
WHERE ua.USER_AUTH_ID = #{authId}
)
AND TAG_CODE = #{tagCode}

mapper.update:
UPDATE
USER_AUTHENTICATION
SET USER_AUTH_PW = #{encodedPassword}
WHERE
USER_AUTH_ID = #{authId}

mapper.select:
SELECT USER_NICKNAME
FROM USERS
WHERE USER_NO = #{value}

mapper.insert:
INSERT INTO USER_TAG_MAP (MAPPING_NO, USER_NO, QUESTION_ID, TAG_CODE) SELECT SEQ_USER_TAG_MAP_NO.NEXTVAL, A.* FROM (
SELECT #{item.userNo} as USER_NO, #{item.questionId} as QUESTION_ID, #{item.tagCode} as TAG_CODE FROM DUAL
) A
